sql:
SELECT machine_id, AVG(average_score) AS overall_average_score
FROM machine_performance
GROUP BY machine_id;

SELECT machine_id, MAX(highest_score) AS highest_score
FROM machine_performance
GROUP BY machine_id;

external_knowledge:
- "Lying dormant" metaphorically refers to machines that have not been played.;
- "Hands of players" symbolizes player usage or interaction with the machines.;
- "Silent as the moon on a cloudy night" metaphorically implies inactivity or absence of usage.

sql:
SELECT machine_id, AVG(average_score) AS AverageScore
FROM machine_performance
GROUP BY machine_id;

external_knowledge:
- 'Classic machines' refers to machines of the type 'classic'.;
- 'Enchanted grove' is a metaphorical expression for the location named 'location_name'.;
- 'Danced under the timeless tunes' is a metaphorical expression denoting interaction or gameplay with these machines.

sql:
SELECT AVG(score) 
FROM tournament_participants
WHERE tournament_id = 0;

SELECT DISTINCT u.user_name
FROM users u
JOIN machine_maintenance mm ON u.user_name = mm.technician_name;

SELECT machine_id, maintenance_type 
FROM machine_maintenance
WHERE maintenance_type = 'cleaning';

SELECT machine_name, type, manufacturer 
FROM machines 
WHERE machine_id = 0;

SELECT u.user_name, me.earning_amount
FROM users u
JOIN machine_earnings me ON u.user_id = me.machine_id;

SELECT machine_id, earning_amount
FROM machine_earnings
WHERE earning_amount = (SELECT MAX(earning_amount) FROM machine_earnings);
